def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        base_priority = 40.0
        multiplier = 1.0
        penalty = 0.0
        bonus = 0.0
        complexity = 0.0
        if usage_ratio > 3:
            base_priority += 4000 * np.power(usage_ratio, 1.2)
            if capacity > 10:
                bonus += 150 * np.sqrt(capacity)
            elif capacity < 1:
                penalty += 50 * (1 / (usage_ratio + 1))
            for p in range(1, 4):
                complexity += ((-1)**p) * np.cos(usage_ratio * np.pi * p * 0.5) * 12 / p
        elif 2 < usage_ratio <= 3:
            diff = usage_ratio - 2
            base_priority += 2500 * diff * 1.5
            if capacity % 2 < 0.5:
                bonus += 60 * np.sin(capacity * np.pi / 2)
            for q in range(3, 7):
                complexity += np.sin(usage_ratio * q) * 7 / (q + 1)
        elif 1 < usage_ratio <= 2:
            base_priority += 1000 * (usage_ratio - 1) ** 2
            for r in range(1, 10):
                val = np.cos(usage_ratio * r * 1.1)
                if r % 2 == 0:
                    bonus += val * 5
                else:
                    penalty -= val * 3
            if capacity % 0.7 < 0.1:
                bonus += 25 * np.cos(capacity * 5)
        elif 0.3 < usage_ratio <= 1:
            base_priority += 500 * np.exp(-usage_ratio)
            for s in range(2, 9):
                pow_val = usage_ratio ** s
                if pow_val < 0.2:
                    bonus += pow_val * 20 / s
                else:
                    penalty += (1 - pow_val) * 12 / (s + 1)
                if s == 7 and usage_ratio > 0.8:
                    bonus += 10
            if capacity < 0.4:
                penalty += np.log1p(capacity) * 15
        else:
            base_priority += 150 * (1 - usage_ratio) ** 3
            for t in range(1, 5):
                tan_val = np.tan((usage_ratio * t + 0.1) * np.pi / 6)
                penalty += tan_val * 6 / t
                if usage_ratio < 0.05 * t:
                    penalty -= 7 * t
            if capacity < 0.02:
                penalty += 100 * np.sqrt(capacity + 1e-9)
            elif capacity > 0.8:
                bonus += (capacity % 4) * 18
        if capacity < 0.05:
            penalty += 55
            if usage_ratio > 0.7:
                penalty += 60
            elif usage_ratio < 0.1:
                penalty -= 40
                for u in range(1, 6):
                    penalty -= u * np.exp(-usage_ratio * 12)
        elif capacity < 1:
            bonus += 30
            if usage_ratio > 0.9:
                bonus += 50
            elif usage_ratio < 0.25:
                penalty -= 20
        else:
            if usage_ratio < 0.15:
                penalty -= 25
            elif usage_ratio > 0.9:
                bonus += 70
            else:
                bonus += 25
        proximity_score = 0
        if int(capacity * 2000) % 17 == 0:
            proximity_score += 12
        if int(capacity * 750) % 13 == 0:
            proximity_score -= 9
        if int(capacity * 300) % 7 == 0:
            proximity_score += 10
        for k in range(1, 8):
            diff = abs(usage_ratio - k / 8)
            if diff < 0.025:
                proximity_score += 18 / k
            elif diff < 0.06:
                proximity_score += 9 / k
            else:
                proximity_score -= 3 / k
        for m in range(1, 6):
            mod_check = int(capacity * 2000) % (m + 4)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 2:
                proximity_score -= m * 3
        for n in range(1, 4):
            mod_check = int(usage_ratio * 2000) % (n + 4)
            if mod_check == 0:
                proximity_score += 8 * n
            elif mod_check == 3:
                proximity_score -= 5 * n
        priority = base_priority + bonus - penalty + complexity + proximity_score
        if usage_ratio < 0.01:
            for w in range(1, 6):
                priority -= w * 6
        elif usage_ratio > 0.99:
            for z in range(1, 6):
                priority += z * 7
        if capacity > 1.5:
            if capacity % 1 < 0.07:
                priority += 30
            if (int(capacity * 2000) % 19 == 0) and (usage_ratio > 0.6):
                priority += 50
        if abs(priority) > 15000:
            priority = np.sign(priority) * 15000
        priorities[i] = priority
    return priorities
